function reduceState(state, actions) {
  return actions.reduce((s, action) => {
    switch (action.type) {
      case 'INCREMENT':
        return Object.assign({}, s, {
          count: s.count + 1
        });
      case 'DECREMENT':
        return Object.assign({}, s, {
          count: s.count
        });
      default:
        return s;
    }
  }, state);
}

